var e=JSON.parse(`[{"id":"L10_1","type":"dialog","speaker":"SPEAR_PERSONA_NULL_NULL","text":{"KOREA":"골목으로 빠지는 녀석들은 전부 정리했어.","JPN":"路地裏に入った奴らは全部処理したわ。","ENG":"I took care of all the ones who were headed to the alley.","TWN":"逃進巷子裡的傢伙們都處理好了。"},"stage":{"bg":"CITY_STREET_NORMAL_02","bgm":"CSM_BATTLE_NORMAL0","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_PERSONA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SPEAR_PERSONA_NULL_NULL","text":{"KOREA":"그쪽은 어때?","JPN":"そっちはどう？","ENG":"How about you?","TWN":"你那邊呢？"},"stage":{"bg":"CITY_STREET_NORMAL_02","bgm":"CSM_BATTLE_NORMAL0","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_PERSONA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"이쪽은 엄청나게 커다란 침식체가 튀어나왔습니다.","JPN":"こちらはものすごく大きな侵食体が出てきました。","ENG":"A huge C.O. just popped out over here.","TWN":"這邊冒出了一個巨大的侵蝕體。"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CSM_BATTLE_NORMAL0","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"TONFA_MAID_NULL_NULL","text":{"KOREA":"으아아아! 이쪽으로 달려오고 있슴다!","JPN":"うわあああ！　こっちに走ってきてるっす！","ENG":"Ahhhh! It's running this way!","TWN":"啊啊啊！往這邊跑來了！"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CSM_BATTLE_NORMAL0","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"SPEAR_PERSONA_NULL_NULL","text":{"KOREA":"아, 알겠어! 나도 지금 도우러 갈 테니까…!","JPN":"わ、わかった！　今私も助けに行くから……！","ENG":"O-okay! I'll go help, so...!","TWN":"喔，我明白了！這就去幫你……！"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CSM_BATTLE_NORMAL0","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"SPEAR_PERSONA_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"FINLEY_CIA_NULL_NULL","text":{"KOREA":"새로 공수해 온 따끈따끈한 T3 지뢰의 화력을 시험해볼 차례군.","JPN":"新しく手に入れたアツアツのT3地雷の火力を試す番だな。","ENG":"It's time to test the firepower of the new T3 mines that were flown in.","TWN":"是時候測試剛剛運過來的T3地雷的火力了。"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CSM_BATTLE_NORMAL0","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"FINLEY_CIA_NULL_NULL","text":{"KOREA":"격발 시켜!","JPN":"撃発！","ENG":"Detonate it!","TWN":"引爆！"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CSM_BATTLE_NORMAL0","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L29_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"침식체가 있었는데요. 없습니다.","JPN":"侵食体がゴミのようですね。","ENG":"It's gone, like a fart in the wind.","TWN":"剛剛有個侵蝕體，現在沒。"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"SPEAR_PERSONA_NULL_NULL","text":{"KOREA":"침식체 반응이 사라졌어.","JPN":"侵食体の反応が消えたわ。","ENG":"The C.O. signals are gone.","TWN":"侵蝕體反應消失了。"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"SPEAR_PERSONA_NULL_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"SPEAR_PERSONA_NULL_NULL","text":{"KOREA":"고작 지뢰로 저런 큰 녀석을 처리했단 말이야…?","JPN":"地雷であんな大きな奴をやっつけたの……？","ENG":"Those mines took care of a C.O. that big...?","TWN":"你只用地雷就幹掉那麼大一個傢伙……？"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"SPEAR_PERSONA_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"FINLEY_CIA_NULL_NULL","text":{"KOREA":"걱정 말라고. 우리도 카운터만 믿고 빈 손으로 온 게 아니니까.","JPN":"心配するな。俺たちもカウンターだけに頼るつもりはない。手ぶらできたわけではないのだ。","ENG":"Fear not. We didn't come here empty-handed, putting everything on the Counters' shoulders.","TWN":"別擔心。我們也不是空手而來的。"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"FINLEY_CIA_NULL_NULL","text":{"KOREA":"문제가 있다면 꽤 비싼 신품이란 거지.","JPN":"問題があるとすれば、結構高い新品ってとこだな。","ENG":"The problem is that it's an expensive new product.","TWN":"只不過它的價格有些昂貴而已。"},"stage":{"bg":"CITY_STREET_NORMAL","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"FINLEY_CIA_NULL_NULL","text":{"KOREA":"음? 이터니움 실드 소진이 빠르군.","JPN":"うん？　エタニウムシールドの消耗が激しいな。","ENG":"Hmm? The Eternium shield is fading quickly.","TWN":"嗯？永恆之金防護網的消耗速度很快。"},"stage":{"bg":"CITY_STREET_NORMAL_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L38_1","type":"dialog","speaker":"FINLEY_CIA_NULL_NULL","text":{"KOREA":"아까보다 침식계수가 상승한 건가?","JPN":"さっきより侵食係数が上昇したのか？","ENG":"Has the Corruption ray coefficient increased?","TWN":"侵蝕數值又提升了嗎？"},"stage":{"bg":"CITY_STREET_NORMAL_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"SPEAR_PERSONA_NULL_NULL","text":{"KOREA":"침식파 때문인지 코핀 컴퍼니도 이제 연락이 안 닿네요.","JPN":"侵食波のせいなのか、コフィンカンパニーとももう連絡がつかないわよ。","ENG":"I can't reach Coffin Company, probably because of the Corruption ray.","TWN":"或許是因為侵蝕波的干擾，我們與科芬公司失去了聯繫。"},"stage":{"bg":"CITY_STREET_NORMAL_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPEAR_PERSONA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L42_1","type":"dialog","speaker":"FINLEY_CIA_NULL_NULL","text":{"KOREA":"괜찮아. 그들이라면 무사할 테니까.","JPN":"大丈夫。彼らなら無事だろう。","ENG":"It's fine. They'll be all right.","TWN":"沒關係，他們不會有事的。"},"stage":{"bg":"CITY_STREET_NORMAL_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SPEAR_PERSONA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L43_1","type":"dialog","speaker":"FINLEY_CIA_NULL_NULL","text":{"KOREA":"전장 반대편의 애인이 걱정되는 거라면 문자나 남겨두라고.","JPN":"戦場の反対側にいる恋人が心配なら、メッセージでも残しておけ。","ENG":"If you're worried about your lover on the other side of the battlefield, you can always leave a text.","TWN":"如果你擔心另一個戰場的情人，就留個訊息吧。"},"stage":{"bg":"CITY_STREET_NORMAL_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPEAR_PERSONA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L44_1","type":"dialog","speaker":"SPEAR_PERSONA_NULL_NULL","text":{"KOREA":"누가 애인이라는 거예요!","JPN":"誰が恋人だ！","ENG":"Who are you calling my lover?!","TWN":"誰說是情人！"},"stage":{"bg":"CITY_STREET_NORMAL_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FINLEY_CIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPEAR_PERSONA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L48_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"방금이 마지막이었나 본데요?","JPN":"今のが最後だったみたいですよ？","ENG":"That seems to be the last one.","TWN":"剛剛那是最後一個？"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":null}}},{"id":"L49_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"깜짝 놀랐네.","JPN":"びっくりした。","ENG":"That startled me.","TWN":"嚇我一跳。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_HATE"}}}},{"id":"L50_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"숲에서 갑자기 튀어나온 게 고라니가 아니라 침식체였을 줄이야.","JPN":"森からいきなり飛び出てきたのがキバノロじゃなくて侵食体だなんて。","ENG":"I thought that was a deer, not a C.O.","TWN":"沒想到從森林裡突然冒出個侵蝕體。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"사장님은 괜찮아?","JPN":"社長は大丈夫？","ENG":"Are you all right, Boss?","TWN":"老闆還好嗎？"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"충격이 좀 있었지만 괜찮네. 옆자리의 펠리세트 양이 받아준 덕분이지.","JPN":"少し衝撃はあったが、大丈夫だ。隣のフェリセット君が受け止めてくれたおかげでな。","ENG":"A bit of an impact, but I'm all right. Félicette took the brunt of the impact.","TWN":"我受了點衝擊，不過還好，多虧了旁邊的費莉塞特。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"…그럼요. 이런 돌발상황에 대비한 훈련을 얼마나 많이 했는데요.","JPN":"……当然です。このような突発的な状況に備えた訓練をたくさんしてきましたから。","ENG":"...Of course. I trained a lot in preparation for unexpected situations like these.","TWN":"……當然了，我們為這種突發情況訓練過不知多少次了。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"앗, 펠리세트 씨! 언제부터 사장님 밑에 깔려 계셨던 거예요?!","JPN":"あっ、フェリセットさん！　いつから社長の下敷きに！？","ENG":"Oh, Félicette! How long have you been squashed under Boss?!","TWN":"啊，費莉塞特！你什麼時候被老闆壓在下面的？"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L9_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"방금 전이요.","JPN":"さっきからです。","ENG":"Not long. Just a bit.","TWN":"就在剛才。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"그리고 깔린 게 아니라 제가 코치를 받아낸 거라니까요?","JPN":"それから、下敷きになったんじゃなくて私がコーチを受け止めたんです。","ENG":"But I'm not squashed under him. I saved him.","TWN":"而且我不是被壓住，而是我接住教練。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"그 말에 설득력이 있으려면 펠리세트의 몸집이 더 커져야할 것 같은데.","JPN":"その話に説得力を持たせたいのなら、フェリセットの図体がもっと大きくならないとダメだと思うけど。","ENG":"I think you're too small to make it sound convincing.","TWN":"費莉塞特的體型要再大一點，這句話才有可信度吧。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"시동이 안 걸려. 부딪힌 뒤로 차가 완전히 퍼졌네.","JPN":"エンジンがかからない。ぶつかったせいで車が完全にダメになったな。","ENG":"The car won't start. The car got wrecked after crashing into that C.O.","TWN":"汽車無法發動，應該是被剛剛的衝撞徹底撞壞了。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"걸어서 가는 수밖에 없겠어.","JPN":"歩いていくしかないか。","ENG":"Seems like we have no choice but to walk.","TWN":"只能走過去。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"그런데… 여긴 어디죠?","JPN":"ところで……ここはどこでしょう？","ENG":"But... where are we?","TWN":"但是……這是什麼地方？"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L20_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"샤레이드는 전부 도시인 줄 알았는데, 여긴 온통 산하고 나무 밖에 안 보이네요.","JPN":"シャレードって全部都市だと思ってたのに、ここには木しかありませんね。","ENG":"I thought Charade only had urban areas. This is all mountains and trees.","TWN":"我以為查雷德只有城市，這邊卻只有山和樹木。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"이런 조용한 외곽에 뭐가 있길래 침식체가 모여드는 걸까요?","JPN":"こんな静かな外郭に何があって、侵食体は集まっているのでしょう？","ENG":"What's making the C.O.s gather in a quaint outskirts area like this?","TWN":"是什麼吸引了侵蝕體聚集到如此寧靜的郊外？"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그건 직접 확인해보면 곧 알게 되겠지.","JPN":"それは、直接確かめればすぐにわかるだろう。","ENG":"We'll figure that out soon enough.","TWN":"親眼去看看就知道了。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"다들 준비 됐지?","JPN":"みんな、準備はいい？","ENG":"Are you all ready?","TWN":"大家都準備好了吧？"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"가자.","JPN":"行こう。","ENG":"Let's go.","TWN":"我們走。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"서막이 오르고, 극의 주연들이 단서를 좇기 시작했습니다.","JPN":"序幕が始まり、劇の主演たちが手がかりを追い始めました。","ENG":"As the opening scene unfolds, the lead characters of the play start following the clues.","TWN":"序幕已經拉開，劇中的演員開始尋找線索了。"},"stage":{"bg":"MS_1201","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_SIXWING_CA_ACTOR_IN_TRAILER_13"},{"id":"L31_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"작고 사소했던 사건은 들불처럼 겉잡을 수 없이 커지고, 누가 이 모든 것을 촉발한 악역인지 사람들은 곧 알게 될 겁니다.","JPN":"小さく些細だった事件は野火のように手がつけられないほど燃え上がり、火付け役の悪人は誰なのか、皆が知ることになるでしょう。","ENG":"Minor, trivial incidents spread like wildfire, and the audience will soon figure out the true villain that triggered this entire narrative.","TWN":"一個微不足道的小事件會像野火一樣一發不可收拾，人們很快就會意識到究竟誰是始作俑者。"},"stage":{"bg":"MS_1201","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_SIXWING_CA_ACTOR_IN_TRAILER_14"},{"id":"L32_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"이걸로 모든 준비는 끝났어요, 암군이여.","JPN":"これですべての準備が整いました、暗君よ。","ENG":"All the preparations are complete, Ignorant Monarch.","TWN":"準備完畢了，昏君。"},"stage":{"bg":"MS_1201","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_SIXWING_CA_ACTOR_IN_TRAILER_15"},{"id":"L33_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"당신이라는 시련이 그녀가 선택한 세계를 무너뜨릴 때…","JPN":"あなたという試練が、彼女の選んだ世界を崩す時……","ENG":"When the trial that is yourself brings ruin to the world she chose...","TWN":"當以你為名的試煉毀掉她選擇的世界時……"},"stage":{"bg":"MS_1201","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_SIXWING_CA_ACTOR_IN_TRAILER_16"},{"id":"L36_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"비로소 그녀도… 자기자신이 누구인지 깨닫게 되겠죠.","JPN":"彼女もようやく……自身の正体を知ることになるでしょう。","ENG":"That is when she... will realize who she is.","TWN":"她也會明白……自己究竟是誰。"},"stage":{"bg":"MS_1201","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_SIXWING_CA_ACTOR_IN_TRAILER_17"}]`);export{e as default};